import Link from "next/link";
import Image from "next/image";
import { notFound } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Vessel } from "../../lib/types";

// TEMP: use API instead of scraper
async function getVessels() {
  const res = await fetch("http://localhost:3000/api/vessels", {
    cache: "no-store",
  });

  if (!res.ok) return [];
  return res.json();
}

export default async function VesselDetailsPage({
  params,
}: {
  params: { id: string };
}) {
  const vesselId = Number(params.id);

  if (!vesselId) return notFound();

  const vessels: Vessel[] = await getVessels();

  const vessel = vessels.find((v: Vessel) => v.id == vesselId);

  if (!vessel) return notFound();

  return (
    <div className="container mx-auto px-4 py-8 max-w-5xl">

      <Link href="/auctions">
        <Button variant="ghost" className="mb-4">
          ← Back to Auctions
        </Button>
      </Link>

      <div className="flex gap-4 items-center mb-6">
        <h1 className="text-4xl font-bold">{vessel.name}</h1>
        <Badge>{vessel.status}</Badge>
      </div>

      <div className="grid md:grid-cols-2 gap-8">
        <Image
          src={vessel.image}
          alt={vessel.name || "Vessel Details"}
          width={800}
          height={400}
          className="w-full h-[400px] object-cover rounded-lg"
          unoptimized
        />

        <div>
          <div className="text-3xl font-bold text-blue-600 mb-4">
            {vessel.price}
          </div>

          <p><b>Location:</b> {vessel.location}</p>
          <p><b>Year:</b> {vessel.year}</p>
          <p><b>Type:</b> {vessel.type}</p>
        </div>

      </div>

      <div className="mt-8">
        <h2 className="text-2xl font-bold">Description</h2>
        <p className="text-gray-600 mt-2">{vessel.description}</p>
      </div>

    </div>
  );
}